    pub fn assert_static_error(&self, mut cond: Value, mut message: Value, mut calculatedOutput: Value, mut storedOutput: Value, optional_args: &[Value]) {
        let mut key = get_arg(optional_args, 0, Value::Null);
        //  -----------------------------------------------------------------------------
        //  --- Init of static tests functions------------------------------------------
        //  -----------------------------------------------------------------------------
        // Fast path: the error message is only consumed when the assertion
        // fails, but `jsonStringify` of the (possibly large) computed and
        // stored outputs happens here on EVERY leaf/branch comparison.
        // That is cheap in JS but O(tree²) in the Rust port (each level
        // re-serialises its whole subtree) — it made `--responseTests`
        // take minutes. Bail out before stringifying when the check holds.
        if is_true(&cond) {
            return;
        }
        let mut calculatedString: Value = jsonStringify(calculatedOutput.clone());
        let mut storedString: Value = jsonStringify(storedOutput.clone());
        let mut errorMessage: Value = message.clone();
        if !is_equal(&key, &Value::Null) {
            errorMessage = add(&add(&Value::Str("[".to_string()), &key), &Value::Str("]".to_string()));
        }
        errorMessage = add(&errorMessage, &add(&add(&add(&Value::Str(" computed: ".to_string()), &storedString), &Value::Str(" stored: ".to_string())), &calculatedString));
        assert(cond.clone(), &[errorMessage.clone()]);
}

