                let mut newUrlParams: Value = self.urlencoded_to_dict(newUrlQuery.clone());
                self.assert_new_and_stored_output(exchange.clone(), skipKeys.clone(), newUrlParams.clone(), storedUrlParams.clone(), &[]);
                return Value::Bool(true);
